#include<bits/stdc++.h>
#define int long long
#pragma GCC optimize(2)
using namespace std;
const int maxn=5e5+5;
int dp[maxn];;
struct node
{
	int a,b;
}l[maxn];
bool cmp(node x,node y)
{
	return x.b<y.b;
}
signed main()
{
	ios::sync_with_stdio(false);
	cin.tie(0);
	cout.tie(0);
	int n;
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>l[i].a;
	 } 
	 for(int i=1;i<=n;i++)
	 {
	 	cin>>l[i].b;
	 }
	 sort(l+1,l+n+1,cmp);
	 int ans=0,cnt=0;
	 for(int i=1;i<=n;i++)
	 {
	 	for(int j=min(cnt,l[i].b);j>=0;j--)
	 	{
	 		dp[j+l[i].b]=max(dp[j+l[i].b],dp[j]+l[i].a*(l[i].b-1));
		 }
		 cnt+=l[i].b;
	 }
	 for(int i=1;i<=maxn-5;i++)
	 {
	 	ans=max(ans,dp[i]);
	 }
	for(int i=1;i<=n;i++)
	{
		ans+=l[i].a;
	}
	cout<<ans;
	return 0;
}
